class Solution {
    public long minEnd(int n, int x) {
        long res = (long) x;
        long bit = 1;
        for (int i = 1; i < n; i++) {
            long next = res;
            while ((next & x) != x) {
                next += bit;
            }
            res = next;
            bit <<= 1;
        }
        return res;
    }
}

